import ast

def _parse_arg(raw):
    try:
        return ast.literal_eval(raw)
    except Exception:
        return raw

_inputs = []
try:
    while True:
        _inputs.append(input())
except EOFError:
    pass
a = _parse_arg(_inputs[0]) if len(_inputs) > 0 else ""
b = _parse_arg(_inputs[1]) if len(_inputs) > 1 else ""

print(sum_numbers(a, b))

